// COMPLETE, COMPILABLE C code
#include <stdio.h>
#define MOD 20011
int dp[301][301][301];
int main() {
    int R, C, d;
    scanf("%d %d %d", &R, &C, &d);
    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            int val;
            scanf("%d", &val);
            if (i == 0 && j == 0) {
                dp[i][j][0] = val;
            } else {
                for (int k = 0; k <= d; k++) {
                    if (k > 0) {
                        dp[i][j][k] = (dp[i][j][k] + dp[i][j-1][k-1]) % MOD;
                    }
                    if (k < d) {
                        dp[i][j][k] = (dp[i][j][k] + dp[i-1][j][k+1]) % MOD;
                    }
                }
            }
        }
    }
    printf("%d\n", dp[R-1][C-1][0]);
    return 0;
}

